const input = $input.first().json;
const body = input.body || input;

const business_id = body.business_id || '';
const content_id = body.content_id || '';
const caption = body.caption || '';
const product_image_url = body.product_image_url || body.image_url || '';
const platform = body.platform || 'instagram';
const attempt = parseInt(body.attempt || '1', 10);

if (!business_id) throw new Error('business_id is required');

return [{ json: { business_id, content_id, caption, product_image_url, platform, attempt } }];

const input = $('Extract Data').first().json;
const brandRaw = $('Fetch Brand DNA').first().json;
const bizRaw = $('Fetch Business').first().json;

const brandArr = Array.isArray(brandRaw) ? brandRaw : [brandRaw];
let brandDna = {};
try {
  const raw = brandArr[0]?.brand_dna;
  brandDna = typeof raw === 'string' ? JSON.parse(raw) : (raw || {});
} catch {}

const biz = Array.isArray(bizRaw) ? bizRaw[0] || {} : bizRaw || {};
const industry = biz.industry || brandDna?.brand_identity?.industry || 'business';

return [{ json: {
  ...input,
  business_name: biz.business_name || '',
  industry,
  brand_tone: biz.brand_tone || brandDna?.brand_identity?.voice_tone || 'professional',
  target_audience: biz.target_audience || brandDna?.audience?.primary_demographic || '',
  location: biz.location || '',
  primary_language: biz.primary_language || 'English',
  visual_style: brandDna?.brand_identity?.visual_style || '',
  color_direction: brandDna?.brand_identity?.color_direction || '',
  personality_type: brandDna?.brand_identity?.personality_type || '',
  content_pillars: brandDna?.content_strategy?.content_pillars || [],
  hook_formulas: brandDna?.content_strategy?.hook_formulas || [],
  trending_formats: brandDna?.trend_intelligence?.current_trending_formats || [],
  brand_dna_summary: JSON.stringify(brandDna).slice(0, 1500)
} }];

const ctx = $('Merge Brand Context').first().json;
const trendsRaw = $input.first().json || {};
const trends = (trendsRaw.organic_results || []).slice(0, 5).map(r => r.snippet || r.title || '').filter(Boolean).join('\n');

// Detect product type from caption, industry, or image URL
const captionLower = (ctx.caption || '').toLowerCase();
const industryLower = (ctx.industry || '').toLowerCase();
let productType = 'general';
if (industryLower.includes('food') || industryLower.includes('restaurant') || captionLower.includes('food')) productType = 'food';
else if (industryLower.includes('fashion') || industryLower.includes('clothing') || captionLower.includes('outfit')) productType = 'fashion';
else if (industryLower.includes('fitness') || industryLower.includes('gym') || captionLower.includes('workout')) productType = 'fitness';
else if (industryLower.includes('beauty') || industryLower.includes('cosmetic') || captionLower.includes('skincare')) productType = 'beauty';
else if (industryLower.includes('tech') || industryLower.includes('software') || captionLower.includes('app')) productType = 'tech';
else if (industryLower.includes('real estate') || captionLower.includes('property')) productType = 'real_estate';
else if (industryLower.includes('travel') || captionLower.includes('travel')) productType = 'travel';
else if (industryLower.includes('auto') || captionLower.includes('car')) productType = 'automotive';

return [{ json: { ...ctx, trend_context: trends, product_type: productType } }];

