const raw = $input.first().json.content?.[0]?.text || '';
let c = {};
try { c = JSON.parse(raw); }
catch(e) { const m = raw.match(/{[\s\S]*}/); if(m) try { c = JSON.parse(m[0]); } catch(e2) {} }

const ctx = $('Detect Product Type').first().json;
const prompts = c.prompts || [];
const recommended = c.recommended || 0;

if (prompts.length === 0) {
  // Fallback prompt
  prompts.push({
    type: 'studio',
    prompt: `Professional ${ctx.product_type} photography for ${ctx.business_name}, ${ctx.brand_tone} style, ${ctx.visual_style || 'clean modern aesthetic'}, 8K, ultra sharp`,
    negative_prompt: 'blurry, low quality, watermark, text overlay'
  });
}

return [{ json: {
  ...ctx,
  prompts,
  recommended_prompt_index: recommended,
  total_prompts: prompts.length
} }];

const ctx = $input.first().json;
const prompts = ctx.prompts || [];
return prompts.map((p, i) => ({ json: {
  ...ctx,
  current_prompt: p.prompt,
  current_negative: p.negative_prompt || '',
  current_type: p.type,
  prompt_index: i
} }));

