const genResult = $input.first().json;
const ctx = $('Loop Each Prompt').first().json;

const imageUrl = genResult.image_url || genResult.file_url || genResult.url || '';
const success = !!genResult.success || !!imageUrl;

if (!success) {
  console.error(`[WF09] Image generation failed for prompt type ${ctx.current_type}`);
}

return [{ json: {
  business_id: ctx.business_id,
  content_id: ctx.content_id,
  caption: ctx.caption,
  platform: ctx.platform,
  attempt: ctx.attempt,
  prompt_type: ctx.current_type,
  prompt_index: ctx.prompt_index,
  generated_url: imageUrl,
  generation_success: success,
  model_used: genResult.model_used || 'unknown',
  business_name: ctx.business_name,
  product_type: ctx.product_type
} }];

const scoreResult = $input.first().json;
const ctx = $('IF Generation Success').first().json;

const score = scoreResult.total_score || scoreResult.score || 0;
const breakdown = scoreResult.breakdown || {};
const verdict = scoreResult.verdict || (score >= 7 ? 'approved' : score >= 5 ? 'regenerate' : 'flag');

return [{ json: {
  ...ctx,
  content_score: score,
  score_breakdown: breakdown,
  verdict,
  improvement_notes: scoreResult.improvement_notes || [],
  improved_prompt: scoreResult.improved_prompt || null
} }];

const ctx = $input.first().json;
return [{ json: {
  approved: true,
  content_id: ctx.content_id,
  image_url: ctx.generated_url,
  score: ctx.content_score,
  prompt_type: ctx.prompt_type,
  model_used: ctx.model_used
} }];

const ctx = $input.first().json;
return [{ json: {
  approved: false,
  flagged: true,
  content_id: ctx.content_id,
  score: ctx.content_score,
  reason: ctx.improvement_notes,
  attempt: ctx.attempt
} }];

// Generation failed — log and continue to next prompt
const ctx = $input.first().json;
console.error(`[WF09] Generation failed for business ${ctx.business_id}`);
return [{ json: { ...ctx, status: 'generation_failed' } }];
